  (a1:Address),
  (a2:Address),

  // Other related entities/intermediaries/officers
  (e3:Entity),
  (o2:Officer),
  (i2:Intermediary),

WHERE
  // Incorporation date validation (if applicable)
  e1.incorporation_date = '18-MAY-1983' OR e2.incorporation_date = '18-MAY-1983',

  // Ensure e1/e2 are distinct (avoid duplicates)
  e1 != e2,

  // Check if e1 is an intermediary_of (if applicable)
  EXISTS {
    (e1)-[:intermediary_of]->(i1)
  },

  // Check if e1 has an officer_of relationship (if applicable)
  EXISTS {
    (e1)-[:officer_of]->(o1)
  },

  // Check if e1 is same_company_as another entity
  EXISTS {
    (e1)-[:same_company_as]->(e3)
  },

  // Check if e1 has a registered address
  EXISTS {
    (e1)-[:registered_address]->(a1)
  },

  // Check for similar/connected relationships (e.g., same_name_as)
  EXISTS {
    (e1)-[:same_name_as]->(other1)
  },

  // Check for same_name_as to another entity
  EXISTS {
    (e1)-[:same_name_as]->(e3)
  },

  // Additional constraints (optional)
  // Example: Validate if i1 exists and is related to e1
  i1 IS NOT NULL AND EXISTS { (e1)-[:intermediary_of]->(i1) },

  // Example: Validate if o1 exists and is related to e1
  o1 IS NOT NULL AND EXISTS { (e1)-[:officer_of]->(o1) },

