  e3 IS NOT NULL AND EXISTS { (e1)-[:same_company_as]->(e3) },

  // Example: Validate if other1 is a valid same_name_as entity
  other1 IS NOT NULL AND EXISTS { (e1)-[:same_name_as]->(other1) },

  // Example: Validate if a2 is a valid address connection
  a2 IS NOT NULL AND EXISTS { (e1)-[:connected_to]->(a2) },

  // Example: Validate if o2 exists and is related to e1 (if applicable)
  o2 IS NOT NULL AND EXISTS { (e1)-[:officer_of]->(o2) },

  // Example: Validate if i2 exists and is related to e1 (if applicable)
  i2 IS NOT NULL AND EXISTS { (e1)-[:intermediary_of]->(i2) },

  // Ensure uniqueness for each relationship type
  DISTINCT e1, e2, i1, o1, other1, e3, a1, a2, o2, i2
RETURN
  // Extract all relationships with distinct paths
  [r | (e1)-[r]->(a1)] AS entity_address_links,
